/**
 * Lazy-loading utilities for Next.js components.
 *
 * Provides type-safe wrappers around `next/dynamic` with consistent
 * loading fallbacks and SSR handling for heavy components like editors,
 * canvases, 3D renderers and chart libraries.
 *
 * @module lib/performance/lazy-components
 */

import type { ComponentType } from 'react';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Options for lazy-loading a component. */
export interface LazyLoadOptions {
  /** Whether to disable server-side rendering. Defaults to `true`. */
  ssr?: boolean;
  /** Height of the loading skeleton in pixels. Defaults to 400. */
  skeletonHeight?: number;
  /** Additional CSS class for the loading fallback. */
  skeletonClassName?: string;
}

/** A resolved import returning a module with a `default` export. */
export type DynamicImport<P> = () => Promise<{ default: ComponentType<P> }>;

// ---------------------------------------------------------------------------
// Pure helpers
// ---------------------------------------------------------------------------

/**
 * Build CSS class string for loading skeleton.
 */
export function buildSkeletonClass(
  height: number,
  extra?: string,
): string {
  const base = `animate-pulse rounded-lg bg-muted/30`;
  const heightStyle = `h-[${height}px]`;
  const parts = [base, heightStyle, 'w-full'];
  if (extra) parts.push(extra);
  return parts.join(' ');
}

/**
 * Compute a descriptive label for a lazy-loaded module path.
 *
 * @example
 * moduleLabel('@/components/editor/ChatPanel') // "ChatPanel"
 * moduleLabel('recharts')                       // "recharts"
 */
export function moduleLabel(path: string): string {
  const segments = path.split('/');
  const last = segments[segments.length - 1];
  return last ?? path;
}

/**
 * Normalise LazyLoadOptions by filling in defaults.
 */
export function normaliseOptions(opts?: LazyLoadOptions): Required<LazyLoadOptions> {
  return {
    ssr: opts?.ssr ?? false,
    skeletonHeight: opts?.skeletonHeight ?? 400,
    skeletonClassName: opts?.skeletonClassName ?? '',
  };
}

// ---------------------------------------------------------------------------
// Constants — heavy modules that should always use dynamic imports
// ---------------------------------------------------------------------------

/**
 * List of module paths that should NEVER be imported statically in
 * server components or page-level code. Use `next/dynamic` for these.
 */
export const HEAVY_MODULES = [
  'three',
  '@react-three/fiber',
  '@react-three/drei',
  'react-konva',
  'konva',
  'recharts',
  'framer-motion',
  'monaco-editor',
  '@monaco-editor/react',
  'fabric',
  'remotion',
  '@remotion/player',
] as const;

export type HeavyModule = typeof HEAVY_MODULES[number];

/**
 * Check whether a module import path should be dynamically loaded.
 */
export function isHeavyModule(importPath: string): boolean {
  const normalised = importPath.toLowerCase().trim();
  return HEAVY_MODULES.some((m) => normalised === m || normalised.startsWith(`${m}/`));
}

/**
 * Categories of heavy components with recommended skeleton heights.
 */
export const COMPONENT_CATEGORIES = {
  editor:  { height: 600, ssr: false },
  canvas:  { height: 500, ssr: false },
  chart:   { height: 300, ssr: false },
  '3d':    { height: 400, ssr: false },
  video:   { height: 450, ssr: false },
} as const;

export type ComponentCategory = keyof typeof COMPONENT_CATEGORIES;

/** Return value from getCategoryDefaults. */
export interface CategoryDefaults {
  skeletonHeight: number;
  ssr: boolean;
}

/**
 * Get recommended options for a component category.
 */
export function getCategoryDefaults(category: ComponentCategory): CategoryDefaults {
  const cat = COMPONENT_CATEGORIES[category];
  return { skeletonHeight: cat.height, ssr: cat.ssr };
}

// ---------------------------------------------------------------------------
// Preload helper
// ---------------------------------------------------------------------------

/**
 * Map of preloaded modules to avoid re-triggering imports.
 */
const preloadedModules = new Set<string>();

/**
 * Trigger a module preload. Useful for prefetching on hover/focus.
 * Returns `true` if a new preload was started, `false` if already cached.
 */
export function preloadModule(moduleId: string, loader: () => Promise<unknown>): boolean {
  if (preloadedModules.has(moduleId)) return false;
  preloadedModules.add(moduleId);
  loader().catch(() => {
    // Remove from cache on failure so it can be retried
    preloadedModules.delete(moduleId);
  });
  return true;
}

/**
 * Check if a module has been preloaded.
 */
export function isPreloaded(moduleId: string): boolean {
  return preloadedModules.has(moduleId);
}

/**
 * Reset preload cache (useful for tests).
 */
export function resetPreloadCache(): void {
  preloadedModules.clear();
}
